1	import { withDb } from "./db.mjs";
2	
3	export async function ensureSchema(db) {
4	  const collections = await db.listCollections({ name: "accounts" }).toArray();
5	  if (collections.length === 0) {
6	    await db.createCollection("accounts", {
7	      validator: {
8	        $jsonSchema: {
9	          bsonType: "object",
10	          required: ["accountId", "name", "tier", "status", "createdAt"],
11	          properties: {
12	            accountId: { bsonType: "string" },
13	            name: { bsonType: "string" },
14	            tier: { enum: ["strategic", "midmarket", "standard"] },
15	            status: { enum: ["active", "at-risk", "churned"] },
16	            createdAt: { bsonType: "date" },
17	          },
18	        },
19	      },
20	    });
21	  }
22	}
23	
24	if (import.meta.url === `file://${process.argv[1]}`) {
25	  withDb((db) => ensureSchema(db)).then(() => console.log("schema ready")).catch((e) => { console.error(e); process.exit(1); });
26	}
