1	import { readFileSync } from "node:fs";
2	import { MongoClient } from "mongodb";
3	
4	const cfg = JSON.parse(readFileSync(new URL("../db-config.json", import.meta.url), "utf8"));
5	
6	export async function withDb(fn) {
7	  const client = new MongoClient(cfg.uri);
8	  await client.connect();
9	  try { return await fn(client.db(cfg.db)); } finally { await client.close(); }
10	}
11	export { cfg };
12

